INSERT INTO `v1_f5def5dbd06108a324ea581e426a3390072367c9b532ebce61fd3cc656952d67` VALUES (11, 11, 119931, 0, 1, "……プリン作りに\nまったく役立たないの。\nオマエに頼ったミヤコが間違ってたの。", 0, 0, 11026, 0.5, 6);
