INSERT INTO `v1_f5def5dbd06108a324ea581e426a3390072367c9b532ebce61fd3cc656952d67` VALUES (11, 11, 119931, 0, 1, "これもオマエの知り合いに関係あるの？\nオマエの知り合いは\n変なヤツばっかりなの！", 0, 0, 11031, 0.5, 6);
